/* BTHint — notification indicator atom (Figma 658:1960)
 *
 * Renders as a solid red dot (no count) or a red pill/circle
 * containing a count value. Numbers > 99 display as "99+".
 *
 * Modifier classes applied to .bt-hint:
 *   --dot      : no count, plain circle
 *   --count    : has a number inside
 *   --lg/md/sm : size variant
 *   --single   : 1-digit count  (no horizontal padding on md/sm)
 *   --multi    : 2-digit count  (4 px horizontal padding on md/sm)
 *   --overflow : 99+ count      (wider horizontal padding on lg)
 */

.bt-hint {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--radius-rd);
  flex-shrink: 0;
}

/* ── Dot ────────────────────────────────────────────────────────────────── */

.bt-hint--dot {
  background: var(--color-ext-error);
}

.bt-hint--dot.bt-hint--lg { width: 16px; height: 16px; }
.bt-hint--dot.bt-hint--md { width: 10px; height: 10px; }
.bt-hint--dot.bt-hint--sm { width: 8px;  height: 8px; }

/* ── Count (base) ───────────────────────────────────────────────────────── */

.bt-hint--count {
  background: var(--color-ext-error);
  color: var(--text-inverse);
  font-family: var(--typography-font-family-sans);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  white-space: nowrap;
}

/* ── Count — Large ──────────────────────────────────────────────────────── */

.bt-hint--count.bt-hint--lg {
  font-size: var(--typography-font-size-sm);
  height: 24px;
  min-width: 24px;
  padding: var(--space-xs);
}

/* 99+ needs wider horizontal padding on large */
.bt-hint--count.bt-hint--lg.bt-hint--overflow {
  padding: var(--space-xs) var(--space-sm);
  min-width: auto;
}

/* ── Count — Medium ─────────────────────────────────────────────────────── */

.bt-hint--count.bt-hint--md {
  font-size: var(--typography-font-size-sm);
  height: 16px;
  min-width: 16px;
  padding: 0;
}

.bt-hint--count.bt-hint--md.bt-hint--multi,
.bt-hint--count.bt-hint--md.bt-hint--overflow {
  padding: 0 var(--space-xs);
}

/* ── Count — Small ──────────────────────────────────────────────────────── */

.bt-hint--count.bt-hint--sm {
  font-size: var(--typography-font-size-2xs);
  height: 16px;
  min-width: 16px;
  padding: 0;
}

.bt-hint--count.bt-hint--sm.bt-hint--multi,
.bt-hint--count.bt-hint--sm.bt-hint--overflow {
  padding: 0 var(--space-xs);
}

/**
 * BTHint — notification indicator atom.
 *
 * Renders as a red dot or a red badge containing a count value.
 * Numbers > 99 are automatically clamped to "99+".
 *
 * @example
 * // Dot indicator (no count)
 * <BTHint />
 * <BTHint size="sm" />
 *
 * @example
 * // Count badge
 * <BTHint count={5} />
 * <BTHint count={22} size="md" />
 * <BTHint count={150} />  // renders "99+"
 */
import './BTHint.css';
import type { BTHintProps } from './BTHint.types';

export function BTHint({ count, size = 'lg', className }: BTHintProps) {
  const displayText: string | null =
    count === null || count === undefined
      ? null
      : count > 99
        ? '99+'
        : String(count);

  const isDot = displayText === null;
  const isOverflow = displayText === '99+';
  const isSingle = displayText !== null && displayText.length === 1;
  const isMulti = displayText !== null && displayText.length === 2;

  const classes = [
    'bt-hint',
    `bt-hint--${size}`,
    isDot ? 'bt-hint--dot' : 'bt-hint--count',
    isOverflow && 'bt-hint--overflow',
    isSingle && 'bt-hint--single',
    isMulti && 'bt-hint--multi',
    className,
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <span className={classes} role="status" aria-label={displayText ?? 'notification'}>
      {!isDot && displayText}
    </span>
  );
}

BTHint.displayName = 'BTHint';

export type BTHintSize = 'lg' | 'md' | 'sm';

export interface BTHintProps {
  /**
   * The count to display. When null or undefined the hint renders as a dot.
   * Values > 99 are displayed as "99+".
   */
  count?: number | null;
  /**
   * Visual size of the hint.
   * @default 'lg'
   */
  size?: BTHintSize;
  /** Additional CSS class names. */
  className?: string;
}
